// ignore_for_file: depend_on_referenced_packages, avoid_print

/// Standalone lint rule scanner that runs saropa_lints rules against
/// any Dart project without requiring the target to have saropa_lints
/// as a dependency.
///
/// Reads the project's `analysis_options.yaml` (generated by `init`)
/// to determine which rules to run, unless [tier] is set. If no config
/// exists and no tier is set, returns null to signal the caller to
/// prompt the user to run `init` first.
library;

import 'dart:io' as io;

import 'package:analyzer/analysis_rule/rule_context.dart';
import 'package:analyzer/dart/analysis/utilities.dart';
import 'package:analyzer/dart/ast/ast.dart' show AstVisitor, CompilationUnit;
import 'package:analyzer/error/listener.dart';
import 'package:analyzer/file_system/physical_file_system.dart';
import 'package:analyzer/src/string_source.dart';
import 'package:path/path.dart' as p;

import '../init/cli_args.dart' show tierOrder;
import '../../saropa_lints.dart';
import 'capturing_registry.dart';
import 'scan_config.dart';
import 'scan_diagnostic.dart';
import 'scan_rule_context.dart';
import 'scan_walker.dart';

/// Optional sink for progress and error messages. When null, output goes
/// to stdout (messages) and stderr (progress). When set, all output is
/// sent to this callback so callers can suppress or redirect.
typedef ScanMessageSink = void Function(String message);

/// Scans Dart files using saropa_lints rules without the plugin framework.
class ScanRunner {
  ScanRunner({
    required this.targetPath,
    this.dartFiles,
    this.tier,
    this.messageSink,
    this.applyExclusionsToFileList = true,
  });

  /// Project root: config is loaded from here and relative [dartFiles] are resolved against it.
  final String targetPath;

  /// Optional explicit list of Dart files to scan. When null or empty, files are discovered under [targetPath].
  final List<String>? dartFiles;

  /// Optional tier name (e.g. `essential`, `recommended`, `pedantic`). When set, the rule set is taken from this tier and the project's `diagnostics:` section is not used.
  final String? tier;

  /// Optional sink for all messages. When null, messages go to stdout and progress to stderr.
  final ScanMessageSink? messageSink;

  /// When [dartFiles] is provided, whether to apply the same exclusions as directory discovery (e.g. `.g.dart`, `build/`). Default true.
  final bool applyExclusionsToFileList;

  void _out(String message) {
    if (messageSink != null) {
      messageSink!(message);
    } else {
      print(message);
    }
  }

  void _err(String message) {
    if (messageSink != null) {
      messageSink!(message);
    } else {
      io.stderr.writeln(message);
    }
  }

  void _progress(String message) {
    if (messageSink != null) {
      messageSink!(message);
    } else {
      io.stderr.write(message);
    }
  }

  /// Runs the scan and returns all diagnostics found.
  ///
  /// Returns `null` if no configuration was found and no [tier] was set (caller should tell
  /// the user to run `init` first), or if [tier] was set to an unknown value.
  List<ScanDiagnostic>? run() {
    final ruleNames = _resolveRuleNames();
    if (ruleNames == null) return null;

    if (ruleNames.isEmpty) {
      _out('All rules are disabled in the configuration.');
      return const [];
    }

    SaropaLintRule.enabledRules = ruleNames;
    SaropaLintRule.disabledRules = null;
    final rules = getRulesFromRegistry(ruleNames);
    // Copy nullable to local so promotion applies (avoid_nullable_interpolation).
    final tierLabel = tier;
    if (tierLabel != null) {
      _out('Loaded ${rules.length} rules for tier: $tierLabel');
    } else {
      _out('Loaded ${rules.length} rules from analysis_options.yaml');
    }

    final filesToScan = _resolveDartFiles();
    if (filesToScan.isEmpty) {
      _out('No .dart files found in: $targetPath');
      return const [];
    }
    _out('Scanning ${filesToScan.length} files...\n');

    final registrations = _registerRules(rules);
    return _scanFiles(filesToScan, registrations);
  }

  /// Resolves enabled rule names: from [tier] if set (validated via [tierOrder]), otherwise from project config.
  Set<String>? _resolveRuleNames() {
    // Copy nullable to local for field promotion (avoid_nullable_interpolation).
    final tierLabel = tier;
    if (tierLabel != null) {
      final normalized = tierLabel.toLowerCase();
      if (!tierOrder.contains(normalized)) {
        _out(
          "Unknown tier: '$tierLabel'. Valid tiers: ${tierOrder.join(', ')}",
        );
        return null;
      }
      return getRulesForTier(normalized);
    }
    return _loadRulesFromConfig();
  }

  /// Loads enabled rules from the project's analysis_options.yaml.
  ///
  /// Returns null if no config file or no diagnostics section found.
  Set<String>? _loadRulesFromConfig() {
    final config = loadScanConfig(p.absolute(targetPath));
    if (config == null) {
      final absPath = p.absolute(targetPath);
      _out('No saropa_lints configuration found in:');
      _out('  $absPath/analysis_options.yaml');
      _out('');
      _out('Run init first to configure rules:');
      _out('  dart run saropa_lints init --target $absPath');
      return null;
    }

    SaropaLintRule.disabledRules = config.disabledRules.isEmpty
        ? null
        : config.disabledRules;
    return config.enabledRules;
  }

  /// Resolves files to scan: [dartFiles] if non-empty (relative paths resolved against [targetPath], exclusions applied when [applyExclusionsToFileList]); otherwise discovers under [targetPath].
  List<String> _resolveDartFiles() {
    final raw = dartFiles;
    if (raw == null || raw.isEmpty) {
      return _findDartFiles(targetPath);
    }
    final root = p.absolute(targetPath);
    var list = raw
        .where((path) => path.trim().isNotEmpty)
        .map(
          (path) => p.isAbsolute(path)
              ? p.normalize(path)
              : p.normalize(p.join(root, path)),
        )
        .where((path) => path.endsWith('.dart'))
        .toList();
    if (applyExclusionsToFileList) {
      list = list.where((path) => !_isExcluded(path)).toList();
    }
    return list;
  }

  List<_RuleRegistration> _registerRules(List<SaropaLintRule> rules) {
    final result = <_RuleRegistration>[];
    final dummyUnit = _createContextUnit('', p.absolute(targetPath));

    for (final rule in rules) {
      final registry = CapturingRuleVisitorRegistry();
      final context = ScanRuleContext(definingUnit: dummyUnit);

      try {
        rule.registerNodeProcessors(registry, context);
      } on Object catch (e) {
        _err('  Skipping ${rule.code.lowerCaseName}: $e');
        continue;
      }

      final visitors = registry.capturedVisitors;
      if (visitors.isNotEmpty) {
        result.add(_RuleRegistration(rule, visitors.cast(), context));
      }
    }

    return result;
  }

  List<ScanDiagnostic> _scanFiles(
    List<String> files,
    List<_RuleRegistration> registrations,
  ) {
    final diagnostics = <ScanDiagnostic>[];
    final sw = Stopwatch()..start();

    for (var i = 0; i < files.length; i++) {
      _showProgress(i, files.length, diagnostics.length, files[i], sw);
      _scanSingleFile(files[i], registrations, diagnostics);
    }

    // Clear progress line when using stderr
    if (messageSink == null) {
      io.stderr.write('\r${' ' * 79}\r');
    }
    return diagnostics;
  }

  void _scanSingleFile(
    String filePath,
    List<_RuleRegistration> registrations,
    List<ScanDiagnostic> diagnostics,
  ) {
    final content = io.File(filePath).readAsStringSync();
    final unit = parseString(
      content: content,
      path: filePath,
      throwIfDiagnostics: false,
    ).unit;

    final listener = RecordingDiagnosticListener();
    final source = StringSource(content, filePath);
    final reporter = DiagnosticReporter(listener, source);
    final ctxUnit = _createContextUnit(content, filePath, unit: unit);

    final allVisitors = <AstVisitor<void>>[];
    for (final reg in registrations) {
      reg.context.currentUnit = ctxUnit;
      reg.rule.reporter = reporter;
      allVisitors.addAll(reg.visitors);
    }

    if (allVisitors.isNotEmpty) {
      unit.accept(ScanWalker(allVisitors));
    }

    for (final d in listener.diagnostics) {
      final loc = unit.lineInfo.getLocation(d.offset);
      diagnostics.add(
        ScanDiagnostic(
          ruleName: d.diagnosticCode.lowerCaseName,
          filePath: filePath,
          line: loc.lineNumber,
          column: loc.columnNumber,
          offset: d.offset,
          length: d.length,
          severity: d.diagnosticCode.severity.name,
          problemMessage: d.problemMessage.messageText(includeUrl: false),
        ),
      );
    }
  }

  void _showProgress(
    int index,
    int total,
    int issues,
    String filePath,
    Stopwatch sw,
  ) {
    if (index % 10 != 0) return;
    final elapsed = sw.elapsedMilliseconds / 1000;
    final rate = elapsed > 0 ? (index / elapsed).round() : 0;
    final name = p.basename(filePath);
    _progress(
      '\r  Files: $index/$total | ${elapsed.toStringAsFixed(1)}s'
      ' | $rate/s | Issues: $issues | $name'
      '${' ' * 20}',
    );
  }

  /// Creates a [RuleContextUnit] for the given file content.
  static RuleContextUnit _createContextUnit(
    String content,
    String filePath, {
    CompilationUnit? unit,
  }) {
    final provider = PhysicalResourceProvider.INSTANCE;
    final file = provider.getFile(filePath);
    final listener = RecordingDiagnosticListener();
    final reporter = DiagnosticReporter(
      listener,
      StringSource(content, filePath),
    );
    return RuleContextUnit(
      file: file,
      content: content,
      diagnosticReporter: reporter,
      unit:
          unit ?? parseString(content: content, throwIfDiagnostics: false).unit,
    );
  }

  static List<String> _findDartFiles(String directory) {
    final dir = io.Directory(directory);
    if (!dir.existsSync()) return const [];

    return dir
        .listSync(recursive: true)
        .whereType<io.File>()
        .where((f) => f.path.endsWith('.dart'))
        .where((f) => !_isExcluded(f.path))
        .map((f) => p.normalize(f.path))
        .toList();
  }

  static bool _isExcluded(String path) {
    final n = path.replaceAll('\\', '/');
    return n.contains('/.dart_tool/') ||
        n.contains('/build/') ||
        n.contains('/bin/') ||
        n.contains('/example') ||
        n.contains('.g.dart') ||
        n.contains('.freezed.dart') ||
        n.contains('.gr.dart') ||
        n.contains('.gen.dart') ||
        n.contains('.mocks.dart') ||
        n.contains('.config.dart') ||
        n.contains('/generated/');
  }
}

class _RuleRegistration {
  const _RuleRegistration(this.rule, this.visitors, this.context);
  final SaropaLintRule rule;
  final List<AstVisitor<void>> visitors;
  final ScanRuleContext context;
}
